// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.List;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * A triple stored in several named graphs matches a default-graph pattern once per quad, so a non-DISTINCT query must
 * see the duplicate solutions. The native path used to degrade a pattern whose variables were all bound by earlier
 * patterns into a one-shot existence check, silently collapsing that multiplicity (found by differential fuzzing:
 * native returned {a=s12, b=s13} once where the generic engine returned it twice).
 */
public class LmdbNativeQuadMultiplicityTest {

	private static final String EX = "http://example.com/";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI x = vf.createIRI(EX, "x");
			IRI y = vf.createIRI(EX, "y");
			IRI p1 = vf.createIRI(EX, "p1");
			IRI p2 = vf.createIRI(EX, "p2");
			IRI g1 = vf.createIRI(EX, "g1");
			IRI g2 = vf.createIRI(EX, "g2");
			// both join triples live in two named graphs: the union default graph sees each twice
			conn.add(x, p1, y, g1);
			conn.add(x, p1, y, g2);
			conn.add(x, p2, y, g1);
			conn.add(x, p2, y, g2);
		}
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	@Test
	public void joinPreservesQuadMultiplicity() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(
					"SELECT * WHERE { ?a <" + EX + "p1> ?b . ?a <" + EX + "p2> ?b . }").evaluate());
			assertThat(result)
					.as("2 quads for p1 x 2 quads for p2 = 4 solutions")
					.hasSize(4);
		}
	}

	@Test
	public void unionBranchPreservesQuadMultiplicity() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(
					"SELECT * WHERE { ?b <" + EX + "p1> ?a . { ?a <" + EX + "p2> ?b . } UNION { ?a <" + EX
							+ "p3> ?c . } FILTER(bound(?b)) }")
					.evaluate());
			// the p1 pattern binds (?b=x, ?a=y)... p1 matches (x,y) twice; branch 1 probes (y,p2,x):
			// zero matches; the reverse orientation (?b=x -> ?a=y) probes (y p2 x) which has no quads,
			// so only rows where the correlated probe matches survive
			List<BindingSet> generic = evaluateGeneric(
					"SELECT * WHERE { ?b <" + EX + "p1> ?a . { ?a <" + EX + "p2> ?b . } UNION { ?a <" + EX
							+ "p3> ?c . } FILTER(bound(?b)) }");
			assertThat(result).hasSameSizeAs(generic);
		}
	}

	@Test
	public void countStarSeesQuadMultiplicity() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(
					"SELECT (COUNT(*) AS ?c) WHERE { ?a <" + EX + "p1> ?b . ?a <" + EX + "p2> ?b . }").evaluate());
			assertThat(((Literal) result.get(0).getValue("c")).longValue()).isEqualTo(4L);
		}
	}

	@Test
	public void distinctStillCollapsesDuplicates() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(
					"SELECT DISTINCT ?a ?b WHERE { ?a <" + EX + "p1> ?b . ?a <" + EX + "p2> ?b . }").evaluate());
			assertThat(result).hasSize(1);
		}
	}

	private List<BindingSet> evaluateGeneric(String query) {
		String previous = System.getProperty("rdf4j.lmdb.nativeQueryEngine.enabled");
		try {
			System.setProperty("rdf4j.lmdb.nativeQueryEngine.enabled", "false");
			try (SailRepositoryConnection conn = repository.getConnection()) {
				return QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			}
		} finally {
			if (previous == null) {
				System.clearProperty("rdf4j.lmdb.nativeQueryEngine.enabled");
			} else {
				System.setProperty("rdf4j.lmdb.nativeQueryEngine.enabled", previous);
			}
		}
	}
}
